randomNumber:
// Requires access to .NET's System.Random
open System

// Create a random number generator instance
// It's often better to create one instance and reuse it
let rnd = Random()

// Generate a random integer (0 to Int32.MaxValue - 1)
let randomInt = rnd.Next()
printfn "Random Integer (full range): %d" randomInt

// Generate a random integer within a specific range [min, max)
// Next(minValue, maxValue) - minValue is inclusive, maxValue is exclusive
let minValue = 1
let maxValueExclusive = 101 // To include 100
let randomInRange = rnd.Next(minValue, maxValueExclusive)
printfn "Random Integer (%d-%d): %d" minValue (maxValueExclusive - 1) randomInRange

// Generate a random double between 0.0 and 1.0
let randomDouble = rnd.NextDouble()
printfn "Random Double [0.0, 1.0): %f" randomDouble

// Select a random element from a list or array
let fruits = [ "apple"; "banana"; "cherry" ]
if not (List.isEmpty fruits) then
    let randomIndex = rnd.Next(0, fruits.Length) // Get random index
    let randomFruit = fruits.[randomIndex] // Access element by index
    printfn "Random fruit: %s" randomFruit

fibonacci:
// Function to calculate the Nth Fibonacci number (0-indexed)
// Uses tail recursion with accumulator for efficiency
let fib n =
    let rec fibAcc n a b =
        match n with
        | 0 -> a
        | 1 -> b
        | _ -> fibAcc (n - 1) b (a + b) // Tail recursive call

    // Use bigint for results to handle large numbers
    if n < 0 then invalidArg "n" "Input must be non-negative"
    else fibAcc (int64 n) 0I 1I // Start with F(0)=0, F(1)=1 using bigint literals (I)

// Function to generate first 'count' Fibonacci numbers
let generateFibSequence count =
    if count < 0 then invalidArg "count" "Count must be non-negative"
    [ for i in 0 .. (count - 1) -> fib i ] // Use list comprehension

// Example Usage
let n = 10
printfn "Fibonacci number F(%d): %A" n (fib n)

let numTerms = 15
printfn "First %d Fibonacci numbers:" numTerms
printfn "%A" (generateFibSequence numTerms)

// Example with large number
let largeN = 90
printfn "Fibonacci number F(%d): %A" largeN (fib largeN)

factorial:
open System.Numerics // Required for BigInteger

// Function to calculate factorial N!
// Uses tail recursion with accumulator for efficiency
let factorial n =
    let rec factAcc n acc =
        match n with
        | 0 | 1 -> acc // Factorial of 0 and 1 is 1
        | _ -> factAcc (n - 1) (acc * bigint n) // Tail recursive, use bigint

    if n < 0 then invalidArg "n" "Factorial is not defined for negative numbers."
    // Start accumulator with 1I (bigint 1)
    factAcc n 1I

// Example usage
let num = 5
printfn "Factorial of %d is %A" num (factorial num)

let num = 0
printfn "Factorial of %d is %A" num (factorial num)

let num = 20 // Within int64 range, but use bigint anyway
printfn "Factorial of %d is %A" num (factorial num)

let num = 30 // Requires BigInteger
printfn "Factorial of %d is %A" num (factorial num)

