readFile:
// Using .NET BCL for file operations
open System.IO

let readFileContent (filePath: string) =
    printfn "--- Reading file '%s' ---" filePath
    if File.Exists(filePath) then
        try
            // Read all text into a single string
            let content = File.ReadAllText(filePath)
            printfn "Content read successfully (as single string):"
            printfn "%s" content
            printfn "--- End of content ---"

            // Alternative: Read all lines into a string array
            // let lines = File.ReadAllLines(filePath)
            // printfn "\\nContent as array of lines:"
            // lines |> Array.iter (printfn "Line: %s")

        with // F# exception handling
        | ex -> printfn "Error reading file '%s': %s" filePath ex.Message
    else
        printfn "Error: File not found '%s'" filePath

// Example Usage
let testFileName = "fsharp_read_test.txt"

// Create a dummy file
try
    File.WriteAllLines(testFileName, [|"Line 1 from F#."; "Second line."|])
    printfn "Created dummy file '%s'" testFileName
    readFileContent testFileName
finally // Ensure cleanup happens
    if File.Exists(testFileName) then
        File.Delete(testFileName)
        printfn "Cleaned up dummy file '%s'" testFileName

// Test non-existent file
readFileContent "non_existent_file.txt"
